;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@command title="Which button will you press?" cancel=true
@select text="23Ｆ" exp='tf.result = ["ラドミラの塔23Ｆ", "up"]'
@select text="17Ｆ" exp='tf.result = ["ラドミラの塔17Ｆ", "down"]'
@select text="No" exp='tf.result = []'
[ask]
@elevator map=&'tf.result[0]' lift=&'tf.result[1]' cond='tf.result[0] !== void'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@question title="<y>Will you drink water from the gushing spring?" cancel=true
[if exp='tf.result']
	@eval exp='o.噴水.doDamage = o.グランドヒール.doDamage'
	@eval exp='o.噴水.resultMessage = o.グランドヒール.resultMessage'
	@btcmd name=噴水
	@notice text="Party's HP restored!"
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] true

; 戦闘
@monster pos=3 name=ミスリルゴーレム
@callbattle bgm=boss
@delevent

[eventoff]
;-------------------------------------------------------------------------------
